<?php

declare(strict_types=1);

$page_id = get_queried_object_id();
$field = static function ( string $name, mixed $fallback ) use ( $page_id ): mixed {
	$value = function_exists( 'get_field' ) ? get_field( $name, $page_id ) : null;
	return empty( $value ) ? $fallback : $value;
};
$image = static function ( mixed $value, string $fallback ): string {
	$url = is_numeric( $value ) ? wp_get_attachment_image_url( (int) $value, 'full' ) ?: wp_get_attachment_url( (int) $value ) : '';
	return $url ? esc_url( $url ) : $fallback;
};
$apply_url = esc_url( (string) $field( 'vacancies_application_url', 'https://forms.gle/ikGeworjH6wnAdSt6' ) );
$about_gallery = $field( 'vacancies_about_gallery', array( 'img/vacancies/about-1.jpg', 'img/vacancies/about-2.jpg', 'img/vacancies/about-3.jpg' ) );
$team_gallery = $field( 'vacancies_team_gallery', array_map( static fn( int $number ): string => sprintf( 'img/vacancies/team-%02d.jpg', $number ), range( 1, 13 ) ) );
$benefits = $field( 'vacancies_benefits', array(
	array( 'title' => 'Щорічні корпоративи', 'text' => 'Кофі-брейки, спільні поїздки в Карпати, квесткімнати та ігроклуби.', 'icon' => 'img/vacancies/benefit-events-3d.webp' ),
	array( 'title' => 'Постійна підтримка', 'text' => 'Регулярне навчання та щотижневі дзвінки, де команда вирішує робочі питання разом.', 'icon' => 'img/vacancies/benefit-support-3d.webp' ),
	array( 'title' => 'Достойна зарплата', 'text' => 'Зрозуміла система бонусів і навантаження, з якою ви впливаєте на свій дохід.', 'icon' => 'img/vacancies/benefit-pay-3d.webp' ),
) );
$vacancies = $field( 'vacancies_items', array(
	array( 'title' => 'Викладач програмування', 'image' => 'img/vacancies/programming-teacher.jpeg', 'summary' => 'Для енергійних викладачів, які впевнено працюють з комп’ютером і хочуть надихати дітей.', 'details' => '<h3>Хто нам потрібен?</h3><p>Енергійні та вмотивовані викладачі з активним підходом до роботи. Перевагою буде педагогічна або психологічна освіта.</p><h3>Обов’язки</h3><p>Проводити заняття за готовими методичними матеріалами, підтримувати дружню атмосферу, стежити за результатами учнів і вести звітність.</p><h3>Ми пропонуємо</h3><p>Роботу у будні та вихідні, стабільне підвищення оплати залежно від навантаження, навчання за рахунок компанії та сучасні кабінети.</p>' ),
	array( 'title' => 'Викладач англійської мови', 'image' => 'img/vacancies/english-teacher.jpg', 'summary' => 'Для викладачів, які допомагають дітям говорити англійською впевнено та із задоволенням.', 'details' => '<h3>Основні обов’язки</h3><p>Проводити групові заняття двічі на тиждень, перевіряти домашні завдання, мотивувати учнів і працювати у команді з методистом та менеджером.</p><h3>Для нас важливо</h3><p>Педагогічна або філологічна освіта, досвід роботи з дітьми, англійська від B2–C1 і впевнене володіння сучасними технічними засобами.</p><h3>Ми пропонуємо</h3><p>Підтримку команди, сучасні методичні матеріали й можливість професійного розвитку.</p>' ),
	array( 'title' => 'Клієнтський менеджер', 'image' => 'img/vacancies/client-manager.jpg', 'summary' => 'Для уважних менеджерів, яким подобається допомагати батькам обрати навчання для дитини.', 'details' => '<h3>Ваші обов’язки</h3><p>Презентувати школу батькам, організовувати навчальний процес, взаємодіяти з учнями, батьками та викладачами, вести базову фінансову звітність і працювати зі зворотним зв’язком.</p><h3>Сильні сторони</h3><p>Бажання вчитися, досвід продажів, стресостійкість, хороша дикція, вільна українська та самостійність у рішеннях.</p><h3>Ми пропонуємо</h3><p>Стабільну роботу, підтримку команди та прозорі можливості зростання.</p>' ),
) );
