	<section class="vacancies-about" id="about"><div class="container"><div class="vacancies-heading"><p class="vacancies-eyebrow">Про нас</p><h2><?php echo esc_html( (string) $field( 'vacancies_about_title', 'Навчаємо цікаво, легко та ефективно' ) ); ?></h2><div><?php echo wp_kses_post( (string) $field( 'vacancies_about_text', '<p>Logika — успішний освітній проєкт з 2018 року і понад 50 000 випускників. Ми навчаємо дітей 7–17 років програмуванню та англійської онлайн і офлайн.</p><p>Проводимо квести, їздимо в IT-табори та створюємо навчання, до якого хочеться повертатися.</p>' ) ); ?></div></div><div class="vacancies-photo-grid vacancies-photos"><?php foreach ( $about_gallery as $index => $photo ) : ?><img src="<?php echo $image( $photo, sprintf( 'img/vacancies/about-%d.jpg', $index + 1 ) ); ?>" alt="Команда Logika"><?php endforeach; ?></div></div></section>
