	<section class="vacancies-gallery" aria-labelledby="team-gallery"><div class="container"><div class="vacancies-heading"><p class="vacancies-eyebrow">Разом поза роботою</p><h2 id="team-gallery"><?php echo esc_html( (string) $field( 'vacancies_team_gallery_title', 'Наші корпоративні теплі зустрічі' ) ); ?></h2></div><div class="vacancies-team-gallery"><?php foreach ( $team_gallery as $index => $photo ) : $url = $image( $photo, sprintf( 'img/vacancies/team-%02d.jpg', $index + 1 ) ); ?><button class="vacancies-team-gallery__item" type="button" data-vacancies-gallery-src="<?php echo esc_url( $url ); ?>" aria-label="<?php echo esc_attr( sprintf( 'Відкрити фото команди %d', $index + 1 ) ); ?>"><img src="<?php echo esc_url( $url ); ?>" alt="Зустріч команди Logika"></button><?php endforeach; ?></div></div></section>
